import java.util.*;

public class Solution {
    public static long solve(long[] value, long[] limit) {
        int n = value.length;
        List<Pair<Long, Long>> elements = new ArrayList<>();

        // Create a list of elements with their value and limit
        for (int i = 0; i < n; ++i) {
            elements.add(new Pair<>(value[i], limit[i]));
        }

        // Sort elements by value in descending order
        Collections.sort(elements, (a, b) -> {
            if (a.getKey() != b.getKey()) {
                return Long.compare(b.getKey(), a.getKey());
            }
            return Long.compare(a.getValue(), b.getValue());
        });

        // Min-heap to track active elements
        PriorityQueue<Integer> pq = new PriorityQueue<>();
        long total = 0;

        for (int i = 0; i < n; ++i) {
            // Check if the current element can be activated
            if (pq.size() < elements.get(i).getValue()) {
                // Activate the element
                total += elements.get(i).getKey();
                pq.add(i);
            }
        }

        return total;
    }
}
